namespace sv_3c44e4a7a1cc4a9fb9d2bf6b204d6fce.Models;

// Domain records
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

// Service contract
public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

@* Horizontal step progress bar with clickable completed steps *@

<nav aria-label="Application progress">
    <ol class="step-indicator">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepNumber = i + 1;
            var status = GetStepStatus(stepNumber);
            <li class="step-item @status" @onclick="() => HandleStepClick(stepNumber)" role="button"
                aria-current="@(stepNumber == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (CompletedSteps.Contains(stepNumber))
                    {
                        <span aria-hidden="true">✓</span>
                    }
                    else
                    {
                        @stepNumber
                    }
                </span>
                <span class="step-label">@StepNames[i]</span>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "future";
    }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    display: flex;
    justify-content: space-between;
    list-style: none;
    padding: 0;
    margin: 0 0 2rem 0;
    counter-reset: step;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    text-align: center;
}

/* Connector line between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    z-index: 1;
    transition: all 0.2s;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.8rem;
    font-weight: 500;
}

/* Active step */
.step-item.active .step-circle {
    background-color: #0d6efd;
    color: white;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.25);
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

/* Completed step */
.step-item.completed .step-circle {
    background-color: #198754;
    color: white;
    cursor: pointer;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

.step-item.completed:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

/* Future step */
.step-item.future .step-circle {
    background-color: #e9ecef;
    color: #adb5bd;
}

.step-item.future .step-label {
    color: #adb5bd;
}

