@* Horizontal step progress bar with clickable completed steps *@

<nav aria-label="Application progress">
    <ol class="step-indicator">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepNumber = i + 1;
            var status = GetStepStatus(stepNumber);
            <li class="step-item @status" @onclick="() => HandleStepClick(stepNumber)" role="button"
                aria-current="@(stepNumber == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (CompletedSteps.Contains(stepNumber))
                    {
                        <span aria-hidden="true">✓</span>
                    }
                    else
                    {
                        @stepNumber
                    }
                </span>
                <span class="step-label">@StepNames[i]</span>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "future";
    }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

