toolArgs.file_text:
.step-indicator {
    display: flex;
    justify-content: space-between;
    list-style: none;
    padding: 0;
    margin: 0 0 2rem 0;
    counter-reset: step;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    text-align: center;
}

/* Connector line between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    z-index: 1;
    transition: all 0.2s;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.8rem;
    font-weight: 500;
}

/* Active step */
.step-item.active .step-circle {
    background-color: #0d6efd;
    color: white;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.25);
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

/* Completed step */
.step-item.completed .step-circle {
    background-color: #198754;
    color: white;
    cursor: pointer;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

.step-item.completed:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

/* Future step */
.step-item.future .step-circle {
    background-color: #e9ecef;
    color: #adb5bd;
}

.step-item.future .step-label {
    color: #adb5bd;
}

