arguments.file_text:
@using sv_3c44e4a7a1cc4a9fb9d2bf6b204d6fce.Models
@inject IApplicationService ApplicationService

<h4 class="mb-4">Personal Information</h4>

@if (errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (emailError is not null)
        {
            <div class="invalid-feedback">@emailError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private List<string> errors = new();
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        errors.Clear();
        emailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName)) errors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(Model.Email)) errors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(Model.Phone)) errors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(Model.Address)) errors.Add("Address is required.");

        if (errors.Count > 0) return;

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@using sv_3c44e4a7a1cc4a9fb9d2bf6b204d6fce.Models

<h4 class="mb-4">Work History</h4>

@if (errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index + 1"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-2">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> errors = new();

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            if (string.IsNullOrWhiteSpace(e.Company)) errors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(e.Title)) errors.Add($"Position {i + 1}: Job title is required.");
            if (e.StartDate is null) errors.Add($"Position {i + 1}: Start date is required.");
        }

        if (errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

@using sv_3c44e4a7a1cc4a9fb9d2bf6b204d6fce.Models

<h4 class="mb-4">References</h4>

@if (errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   Index="index + 1"
                   CanRemove="References.Count > 1"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-2">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> errors = new();

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 1)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name)) errors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship)) errors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email)) errors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone)) errors.Add($"Reference {i + 1}: Phone is required.");
        }

        if (errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

@using sv_3c44e4a7a1cc4a9fb9d2bf6b204d6fce.Models

<h4 class="mb-4">Review Your Application</h4>

@if (ApplicationId is not null)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch!</p>
    </div>
}
else
{
    @if (SubmissionError is not null)
    {
        <div class="alert alert-danger">@SubmissionError</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="#" @onclick="() => OnEdit.InvokeAsync(1)" @onclick:preventDefault class="text-decoration-none">Edit</a>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a href="#" @onclick="() => OnEdit.InvokeAsync(2)" @onclick:preventDefault class="text-decoration-none">Edit</a>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
