            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name)) errors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship)) errors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email)) errors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone)) errors.Add($"Reference {i + 1}: Phone is required.");
        }

        if (errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

