+@page "/apply"
+@rendermode InteractiveServer
+@using sv_3c44e4a7a1cc4a9fb9d2bf6b204d6fce.Models
+@using sv_3c44e4a7a1cc4a9fb9d2bf6b204d6fce.Components.JobApplication
+@inject IApplicationService ApplicationService
+
+<PageTitle>Job Application</PageTitle>
+
+<div class="container py-4" style="max-width: 800px;">
+    <h2 class="mb-4">Job Application</h2>
+
+    <StepIndicator CurrentStep="currentStep"
+                   CompletedSteps="completedSteps"
+                   StepNames="stepNames"
+                   OnStepClicked="GoToStep" />
+
+    @switch (currentStep)
+    {
+        case 1:
+            <PersonalInfoStep Model="personal" OnNext="AdvanceFromStep" />
+            break;
+        case 2:
+            <WorkHistoryStep Entries="workEntries"
+                             OnNext="AdvanceFromStep" OnBack="GoBack" />
+            break;
+        case 3:
+            <ReferencesStep References="references"
+                            OnNext="AdvanceFromStep" OnBack="GoBack" />
+            break;
+        case 4:
+            <CoverLetterStep @bind-CoverLetter="coverLetter"
+                             OnNext="AdvanceFromStep" OnBack="GoBack" />
+            break;
+        case 5:
+            <ReviewStep Personal="personal"
+                        WorkEntries="workEntries"
+                        References="references"
+                        CoverLetter="coverLetter"
+                        IsSubmitting="isSubmitting"
+                        ApplicationId="applicationId"
+                        SubmissionError="submissionError"
+                        OnEdit="GoToStep"
+                        OnBack="GoBack"
+                        OnSubmit="SubmitApplication" />
+            break;
+    }
+</div>
+
+@code {
+    private int currentStep = 1;
+    private readonly HashSet<int> completedSteps = new();
+
+    private readonly List<string> stepNames = new()
+    {
+        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
+    };
+
+    // Form state
+    private readonly PersonalInfoModel personal = new();
+    private readonly List<WorkEntryModel> workEntries = new() { new() };
+    private readonly List<ReferenceModel> references = new() { new() };
+    private string coverLetter = "";
+
+    // Submission state
+    private bool isSubmitting;
+    private int? applicationId;
+    private string? submissionError;
+
+    private void AdvanceFromStep()
+    {
+        completedSteps.Add(currentStep);
+        if (currentStep < 5) currentStep++;
+    }
+
+    private void GoBack()
+    {
+        if (currentStep > 1) currentStep--;
+    }
+
+    private void GoToStep(int step)
+    {
+        currentStep = step;
+    }
+
+    private async Task SubmitApplication()
+    {
+        isSubmitting = true;
+        submissionError = null;
+
+        try
+        {
+            var application = new JobApplication(
+                new PersonalInfo(personal.FullName, personal.Email, personal.Phone, personal.Address),
+                new WorkHistory(workEntries.Select(e => new WorkEntry(
+                    e.Company, e.Title, e.StartDate!.Value,
+                    e.IsCurrent ? null : e.EndDate, e.Description
+                )).ToList()),
+                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
+                coverLetter
+            );
+
+            applicationId = await ApplicationService.SubmitApplicationAsync(application);
+        }
+        catch (Exception ex)
+        {
+            submissionError = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            isSubmitting = false;
+        }
+    }
+}
+

